123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263ll n,p,w;int t;inline ll ksm(ll a,ll b){	ll res=1;	while(b){		if(b&amp;1) res=(res*a)%p;		a=(a*a)%p;		b&gt;&gt;=1;	}	return (res%p+p)%p;}inline ll lrd(ll x){	return ksm(x,(p-1)&gt;&gt;1);}struct rode{	ll x,y;	inline void intt(ll x_,ll y_){		x=x_;y=y_;	}};inline rode operator * (const rode &amp;a,const rode &amp;b){	rode c;c.intt(((a.x*b.x)%p+a.y*b.y%p*w%p)%p,(a.x*b.y%p+a.y*b.x%p)%p);	return c;}inline rode operator ^ (rode a,ll b){	rode c;c.intt(1,0);	while(b){		if(b&amp;1) c=c*a;		a=a*a;		b&gt;&gt;=1;	}	return c;}inline void solve(ll x){	int if_=lrd(x);	if(if_==p-1) printf("Hola!\n");	else if(if_==0) printf("0\n");	else{		ll q=rand()%p;w=(((q*q)%p-n)%p+p)%p;		while(lrd(w)&lt;=1) q=rand()%p,w=(((q*q)%p-n)%p+p)%p;		rode a;a.intt(q,1);		a=a^((p+1)&gt;&gt;1);		ll ans1=a.x,ans2=p-ans1;		if(ans1&gt;ans2) ans1^=ans2,ans2^=ans1,ans1^=ans2;		printf("%lld %lld\n",ans1,ans2);	}}int main(){	srand(time(0));	scanf("%d",&amp;t);	while(t--){		scanf("%lld%lld",&amp;n,&amp;p);		solve(n);	}	return 0;}
