1234567891011121314151617181920212223#define f(i,x) (K[(i)]*(x)+B[(i)])#define ls(k) k&lt;&lt;1#define rs(k) k&lt;&lt;1|1inline void Change(int k,int l,int r,int z,int y,int id){    // if(id==243) printf("z=%d y=%d\n",z,y);    // printf("k=%d l=%d r=%d z=%d y=%d id=%d v[k]=%d\n",k,l,r,z,y,id,v[k]);    if(l==r){if(!v[k]||f(v[k],l)&lt;f(id,l)) v[k]=id;return;}    int mid=(l+r)&gt;&gt;1;    if(z&lt;=l&amp;&amp;r&lt;=y){        if(!v[k]) v[k]=id;        if(f(v[k],mid)&lt;f(id,mid)) swap(v[k],id);        (f(v[k],l)&lt;f(id,l))?Change(ls(k),l,mid,z,y,id):Change(rs(k),mid+1,r,z,y,id);    }    else{        if(z&lt;=mid) Change(ls(k),l,mid,z,y,id);if(y&gt;mid) Change(rs(k),mid+1,r,z,y,id);    }}inline int Ask(int k,int l,int r,int w){    if(l==r) return v[k];int mid=(l+r)&gt;&gt;1;    int nowid;if(w&lt;=mid) nowid=Ask(ls(k),l,mid,w);else nowid=Ask(rs(k),mid+1,r,w);    // printf("k=%d l=%d r=%d w=%d nowid=%d v[k]=%d\n",k,l,r,w,nowid,v[k]);    return (f(v[k],w)&lt;f(nowid,w))?nowid:v[k];}
