1234567891011121314151617181920212223inline bool spfa(int s){    while(q.size()) q.pop();    bool op=0;    mset(d,INF);mset(vis,0);d[s]=0;q.push(s);vis[s]=1;now[s]=head[s];    while(q.size()){        int top=q.front();q.pop();vis[top]=0;        Next(top){            int to=li[x].to,f=li[x].f,v=li[x].v;if(!f||d[to]&lt;=d[top]+v)continue;            d[to]=d[top]+v;if(!vis[to]) vis[to]=1,q.push(to);now[to]=head[to];        }    }    if(d[t]&gt;=INF) return 0;else return 1;}inline int dinic(int k,int flow){    if(k==t) return flow;int rest=flow,x;vis[k]=1;    for(x=now[k];x&amp;&amp;rest;x=li[x].next){        int to=li[x].to,f=li[x].f,v=li[x].v;        if(!f||d[to]!=d[k]+v||(vis[to]&amp;&amp;to!=t)) continue;int val=dinic(to,min(rest,f));        if(!val) d[to]=INF;li[x].f-=val;li[x^1].f+=val;rest-=val;Ans+=val*v;    }    now[k]=x;    return flow-rest;}

注意 dinic 函数中第三个判断条件不能省。
 的判断一定要放在最后。

