12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970#define ls(k) ch[k][0]#define rs(k) ch[k][1]struct LCT{    inline int Get(int k){return rs(fa[k])==k;}    inline void PushUp(int k){        val[k]=a[k]^val[ls(k)]^val[rs(k)];    }    inline void C(int k){        swap(ls(k),rs(k));tag[k]^=1;    }    inline void PushDown(int k){        if(tag[k]){            C(ls(k));C(rs(k));tag[k]^=1;;        }    }    inline bool Root(int k){        int fat=fa[k];        return ls(fat)!=k&amp;&amp;rs(fat)!=k;    }    inline void rotate(int k){        int y=fa[k];int z=fa[y],x=Get(k);        if(!Root(y)) ch[z][Get(y)]=k;        ch[y][x]=ch[k][x^1];fa[ch[k][x^1]]=y;        ch[k][x^1]=y;fa[y]=k;fa[k]=z;        PushUp(y);PushUp(k);    }    inline void Update(int k){        if(!Root(k)) Update(fa[k]);        PushDown(k);    }    inline void Splay(int k){        Update(k);        for(int f=fa[k];!Root(k);rotate(k),f=fa[k]){            if(!Root(f)) rotate(Get(k)==Get(f)?f:k);        }    }    inline int Access(int k){        int p;        for(p=0;k;p=k,k=fa[k]){            Splay(k);rs(k)=p;PushUp(k);        }        return p;    }    inline void MakeRoot(int k){        k=Access(k);C(k);    }    inline void Split(int x,int y){        MakeRoot(x);Access(y);Splay(y);    }    inline int Find(int k){        Access(k);Splay(k);PushDown(k);        while(ls(k)) k=ls(k),PushDown(k);        Splay(k);return k;    }    inline void Cut(int a,int b){        MakeRoot(a);        if(Find(b)==a&amp;&amp;rs(a)==b&amp;&amp;ls(b)==0){            rs(a)=fa[b]=0;PushUp(a);        }    }    inline void Link(int a,int b){        MakeRoot(a);if(Find(b)==a) return;Splay(a);fa[a]=b;    }    inline void Change(int k,int x){        MakeRoot(k);a[k]=x;PushUp(k);    }    inline int Ask(int a,int b){        Split(a,b);return val[b];    }}lct;
