1234567891011121314151617181920212223242526272829303132333435struct node{    int len,link,ch[26];};struct SAM{    node p[N];    int size,last;    inline SAM(){        p[0].len=0;p[0].link=-1;last=0;    }    inline void insert(int c){        int cur=++size;f[size]++;        p[cur].len=p[last].len+1;        int now=last;        while(now!=-1&amp;&amp;!p[now].ch[c]){            p[now].ch[c]=cur;            now=p[now].link;        }        if(now==-1) p[cur].link=0;        else{            int q=p[now].ch[c];            if(p[now].len+1==p[q].len) p[cur].link=q;            else{                int clone=++size;                p[clone]=p[q];p[clone].len=p[now].len+1;                while(now!=-1&amp;&amp;p[now].ch[c]==q){                    p[now].ch[c]=clone;now=p[now].link;                }                p[q].link=p[cur].link=clone;            }        }        last=cur;    }};SAM sam;
